const payload = $input.item.json.payload || [];
const origem = $('Verificar Condições1').first().json || {};
const incoming = payload
  .filter(function(m) { return m.message_type === 0; })
  .sort(function(a, b) { return a.created_at - b.created_at; });

const webhookId = String(origem.messageId || '');
const idx = incoming.findIndex(function(m) { return String(m.id) === webhookId; });
const sliceEnd = idx >= 0 ? idx + 1 : incoming.length;
const windowSize = 6;
const contextMsgs = incoming.slice(Math.max(0, sliceEnd - windowSize), sliceEnd);

const cleaned = contextMsgs
  .map(function(m) { return String(m.processed_message_content || m.content || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim(); })
  .filter(function(t) { return t.length > 0; });

const uniqueOrdered = [];
for (const t of cleaned) {
  if (!uniqueOrdered.includes(t)) uniqueOrdered.push(t);
}

const lastIncoming = contextMsgs.length ? contextMsgs[contextMsgs.length - 1] : null;
const lastId = lastIncoming ? String(lastIncoming.id) : '';
const currentUserMessage = lastIncoming
  ? String(lastIncoming.processed_message_content || lastIncoming.content || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim()
  : String(origem.content || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

const previousMsgs = uniqueOrdered.filter(function(t) { return t !== currentUserMessage; });
const combined = uniqueOrdered.join(' | ');
const contextForAgent = previousMsgs.slice(-3).join(' | ');

const textNorm = combined.toLowerCase();
const vehicleLex = ['ducato','boxer','jumper','master','sprinter','hr','k2500','h100','daily','transit','iveco','l200','hilux','frontier','towner'];
const foundVehicles = vehicleLex.filter(function(v) { return textNorm.includes(v); });
const years = Array.from(textNorm.matchAll(/\b(19\d{2}|20\d{2})\b/g)).map(function(m) { return m[1]; });
const contextVehicleTerm = (foundVehicles.slice(-2).join(' ') + (years.length ? ' ' + years[years.length - 1] : '')).trim();

const productIntent = /(óleo|oleo|amortec|biela|disco|pastilha|filtro|pe[cç]a|peca|c[oó]digo|preciso|procuro|cot|pre[cç]o|valor|\b\d{1,2}w\d{2}\b|estoque|dispon[ií]vel|tem\s+(o|a|esse|essa|d[ae]))/i;
const forceCatalogSearch = productIntent.test(currentUserMessage);

return [{
  json: {
    isLastMessage: lastId === webhookId,
    lastMessageId: lastId,
    webhookMessageId: webhookId,
    combinedMessage: combined || currentUserMessage,
    currentUserMessage,
    contextForAgent,
    contextVehicleTerm,
    forceCatalogSearch,
    totalPayload: payload.length,
    contextMessageCount: uniqueOrdered.length,
    conversationId: String(origem.conversationId || '')
  }
}];

